<?php
namespace Tests\Feature;
use App\Domain\Media\MediaAssetService;use App\Domain\Media\MediaAssetType;use App\Models\Npc;use App\Models\Shop;use Illuminate\Database\Eloquent\Relations\Relation;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
final class ShopMediaAssetsTest extends TestCase{use RefreshDatabase;
 public function test_npc_and_shop_use_stable_morph_aliases_and_primary_assets(){$service=app(MediaAssetService::class);$npc=Npc::factory()->create();$shop=Shop::factory()->for($npc)->create();$portrait=$service->attach($npc,['asset_type'=>MediaAssetType::PORTRAIT,'disk'=>'public','path'=>'npcs/merchant/portrait.webp','is_primary'=>true]);$banner=$service->attach($shop,['asset_type'=>MediaAssetType::BANNER,'disk'=>'public','path'=>'shops/armory/banner.webp','is_primary'=>true]);$background=$service->attach($shop,['asset_type'=>MediaAssetType::BACKGROUND,'disk'=>'public','path'=>'shops/armory/background.webp','is_primary'=>true]);$this->assertSame('npc',$portrait->mediable_type);$this->assertSame('shop',$banner->mediable_type);$this->assertSame(Npc::class,Relation::getMorphedModel('npc'));$this->assertSame(Shop::class,Relation::getMorphedModel('shop'));$this->assertSame($portrait->id,$npc->primaryMediaAsset(MediaAssetType::PORTRAIT)->firstOrFail()->id);$this->assertSame($banner->id,$shop->primaryMediaAsset(MediaAssetType::BANNER)->firstOrFail()->id);$this->assertSame($background->id,$shop->primaryMediaAsset(MediaAssetType::BACKGROUND)->firstOrFail()->id);$this->assertStringContainsString('shops/armory/banner.webp',$banner->url());}
 public function test_deleting_one_primary_type_preserves_other_shop_assets(){$service=app(MediaAssetService::class);$shop=Shop::factory()->create();$banner=$service->attach($shop,['asset_type'=>MediaAssetType::BANNER,'disk'=>'public','path'=>'shops/test/banner.webp','is_primary'=>true]);$background=$service->attach($shop,['asset_type'=>MediaAssetType::BACKGROUND,'disk'=>'public','path'=>'shops/test/background.webp','is_primary'=>true]);$service->deletePrimary($shop,MediaAssetType::BANNER);$this->assertDatabaseMissing('media_assets',['id'=>$banner->id]);$this->assertDatabaseHas('media_assets',['id'=>$background->id,'asset_type'=>MediaAssetType::BACKGROUND,'is_primary'=>1]);}
}
